[
  {
    "topic": "SVG Chart Label Overlaps",
    "lesson": "When drawing persistent data count labels directly on dynamic line charts, apply asymmetric vertical offsets (e.g., above for Inbound, below for Answered) to prevent label overlaps when lines run in close proximity."
  },
  {
    "topic": "Plan Approval Gate Tagging",
    "lesson": "Always make sure the implementation_plan.md begins with '[APPROVED]' once the user grants consent, as the SDK check triggers a hard gate blockage for write tools unless this literal tag is present."
  },
  {
    "topic": "Heatmap Cell Label Contrast",
    "lesson": "When overlaying text numbers inside a density heatmap grid, dynamically calculate text contrast styling (light text on dark backgrounds, dark text on light backgrounds) based on the cell's normalized value ratio relative to the peak value."
  },
  {
    "topic": "Filtering Call Queue Logs",
    "lesson": "When building call metrics for support queue dashboards using account-level logs, query with direction=Inbound and filter the destination fields against known agent User extensions to exclude direct extension dials (DIDs), internal user calls, and outbound dials from the queue telemetry."
  }
]
